add_shortcode('portfolio_final', 'render_cosmos_infinite_loop');

function render_cosmos_infinite_loop() {
    // 1. PHP : Récupération des images (Inchangé)
    $args = array(
        'post_type'      => 'attachment',
        'post_mime_type' => 'image',
        'post_status'    => 'inherit',
        'posts_per_page' => 300, 
    );

    $query_images = new WP_Query( $args );
    $image_data = array();

    if ( $query_images->have_posts() ) {
        while ( $query_images->have_posts() ) {
            $query_images->the_post();
            $id = get_the_ID();

            $caption_raw = get_post_field('post_excerpt', $id);
            $caption = strtolower(trim(strip_tags($caption_raw)));

            if ($caption === 'none') { continue; }

            $src = wp_get_attachment_image_src( $id, 'large' );

            $cats = array('all');
            if (stripos($caption, 'artiste') !== false) { $cats[] = 'artistes'; }
            if (stripos($caption, 'pro') !== false || stripos($caption, 'business') !== false) { $cats[] = 'pro'; }
            if (stripos($caption, 'particulier') !== false) { $cats[] = 'particuliers'; }

            $video_url = trim(get_post_field('post_content', $id));

            if($src) {
                $image_data[] = array(
                    'url'   => esc_url($src[0]),
                    'w'     => $src[1] ? $src[1] : 800, 
                    'h'     => $src[2] ? $src[2] : 600,
                    'cat'   => $cats,
                    'video' => $video_url 
                );
            }
        }
    }
    wp_reset_postdata();

    if (empty($image_data)) { 
        return '<h2 style="color:white;text-align:center;padding-top:100px;">Aucune image trouvée.</h2>'; 
    }

    $json_images = json_encode($image_data, JSON_HEX_APOS | JSON_HEX_QUOT);

    // --- CONFIGURATION DES LIENS ---
    $logo_url = 'https://lastation-prod.com/wp-content/uploads/2025/12/LOGO_LA_STATION_transp.png'; 
    $lien_site    = get_home_url();
    $about_url    = get_permalink(752);
    $contact_url = get_permalink(752) . '#contact';

    // 2. HTML / CSS / JS
    $output = '
    <script src="https://cdn.jsdelivr.net/gh/studio-freight/lenis@1.0.29/bundled/lenis.min.js"></script>

    <style>
        @import url(\'https://fonts.googleapis.com/css2?family=Manrope:wght@400;600&family=Syne:wght@400;700&display=swap\');

        :root {
            --logo-top: 40px; --logo-left: 57px; --logo-width: 430px; 
            --text-top: 330px; --text-left: 57px; 
            --menu-top: 150px; --menu-right: 57px; 
            --col-width: 23%; 
            --font-titre: "Syne", sans-serif;
            --font-ui: "Manrope", sans-serif;
        }

        /* Masquage des éléments natifs */
        header, #masthead, .site-header, .site-branding, .site-title, .site-description, .site-branding-text, .page-header, .elementor-location-header { 
            display: none !important; 
        }

        html.lenis, html.lenis body { height: auto; }
        .lenis.lenis-smooth { scroll-behavior: auto !important; }
        html.lenis { scroll-behavior: auto !important; }

        html, body { 
            margin: 0; padding: 0; background-color: #000; min-height: 100vh; 
            /* Empêche le rebond élastique sur Mac/iOS pour renforcer l\'effet lourd */
            overscroll-behavior: none; 
            scrollbar-width: none; 
            -ms-overflow-style: none; 
        }
        html::-webkit-scrollbar, body::-webkit-scrollbar { display: none; }

        #cosmos-logo { position: fixed; top: var(--logo-top); left: var(--logo-left); width: var(--logo-width); z-index: 9999; display: block; background: rgba(0, 0, 0, 0.4); backdrop-filter: blur(12px); padding: 15px; border-radius: 12px; }
        #cosmos-logo img { width: 100%; height: auto; display: block; }

        #cosmos-tagline-box { 
            position: fixed; top: var(--text-top); left: var(--text-left); z-index: 9998; 
            background: rgba(0, 0, 0, 0.4); backdrop-filter: blur(12px); border-radius: 12px; 
            padding: 15px 25px; font-family: var(--font-titre); color: rgba(255, 255, 255, 0.9); 
            text-transform: uppercase; font-size: 20px; letter-spacing: 1px; font-weight: 700; 
        }

        #cosmos-nav-container { position: fixed; top: var(--menu-top); z-index: 9999; display: flex; gap: 10px; align-items: center; right: var(--menu-right); }

        .cosmos-btn { background: rgba(0, 0, 0, 0.4); backdrop-filter: blur(12px); border: 0px; color: rgba(255, 255, 255, 0.7); padding: 12px 20px; border-radius: 12px; cursor: pointer; white-space: nowrap; font-family: var(--font-ui); font-size: 13px; text-transform: uppercase; letter-spacing: 1px; font-weight: 600; transition: all 0.3s ease; text-decoration: none; display: inline-block; }
        .cosmos-btn.active, .cosmos-btn:hover { background: rgba(255, 255, 255, 0.1); color: white; }
        .cosmos-link-btn { background: rgba(255, 255, 255, 0.08); }
        .cosmos-sep { width: 1px; height: 30px; background: rgba(255,255,255,0.2); margin: 0 5px; }

        #cosmos-wrapper { 
            padding: 40px; box-sizing: border-box; width: 100%; min-height: 100vh; padding-top: 150px;
        }

        #cosmos-layout { display: flex; justify-content: space-between; align-items: flex-start; gap: 20px; width: 100%; flex-wrap: wrap; }
        .cosmos-col { width: var(--col-width); display: flex; flex-direction: column; gap: 30px; }

        .cosmos-item { 
            width: 100%; position: relative; cursor: pointer; border-radius: 12px; overflow: hidden; 
            box-shadow: 0 10px 30px rgba(0,0,0,0.5); background: #111; 
            transform: translateZ(0);
        }
        .cosmos-item img { 
            width: 100%; height: auto; display: block; 
            transition: transform 0.3s ease, filter 0.3s ease; 
        }
        .cosmos-item:not(.playing):hover img { transform: scale(1.02); filter: brightness(1.1); }

        /* RESPONSIVE TABLETTE */
        @media (max-width: 1024px) {
            :root {
                --logo-top: 40px; --logo-left: 40px;
                --text-top: 260px; --text-left: 40px; 
                --col-width: 48%; 
            }
            #cosmos-logo { width: 300px !important; }
            #cosmos-tagline-box { font-size: 16px; width: auto; }
            .cosmos-link-btn { position: fixed !important; top: 45px !important; padding: 10px 18px !important; z-index: 10000; width: auto !important; }
            a.cosmos-link-btn:last-of-type { right: 40px !important; }
            a.cosmos-link-btn:nth-last-of-type(2) { right: 145px !important; }
            #cosmos-nav-container { position: fixed !important; top: 110px !important; right: 40px !important; left: auto !important; display: flex !important; flex-direction: column !important; align-items: flex-end !important; width: auto !important; gap: 8px; }
            #cosmos-nav-container button.cosmos-btn { padding: 6px 10px !important; font-size: 11px !important; border-radius: 6px !important; margin: 0 !important; width: auto !important; text-align: right !important; }
            .cosmos-sep { display: none !important; }
            #cosmos-wrapper { padding-top: 20px !important; }
        }

        /* RESPONSIVE MOBILE */
        @media (max-width: 767px) {
            :root {
                --logo-top: 20px; --logo-left: 15px;
                --text-top: 130px; --text-left: 15px;
                --col-width: 48%; 
            }
            #cosmos-logo { width: 150px !important; } 
            #cosmos-tagline-box { font-size: 11px !important; padding: 6px 10px !important; }
            .cosmos-link-btn { position: fixed !important; top: 20px !important; z-index: 10001; padding: 8px 12px !important; font-size: 10px !important; width: auto !important; }
            a.cosmos-link-btn:last-of-type { right: 15px !important; }
            a.cosmos-link-btn:nth-last-of-type(2) { right: 100px !important; }
            #cosmos-nav-container { position: fixed !important; top: 65px !important; right: 15px !important; gap: 6px; }
            #cosmos-wrapper { padding: 10px; padding-top: 0px !important; }
            #cosmos-layout { gap: 10px; }
            .cosmos-col { gap: 10px; }
        }
    </style>

    <a href="' . esc_url($lien_site) . '" id="cosmos-logo"><img src="' . esc_url($logo_url) . '" alt="Logo"></a>
    <div id="cosmos-tagline-box">Création de vidéos</div>

    <div id="cosmos-nav-container">
        <button class="cosmos-btn active" onclick="window.cosmosSetFilter(\'all\', this)">Tout</button>
        <button class="cosmos-btn" onclick="window.cosmosSetFilter(\'artistes\', this)">Artistes</button>
        <button class="cosmos-btn" onclick="window.cosmosSetFilter(\'pro\', this)">Professionnels</button>
        <button class="cosmos-btn" onclick="window.cosmosSetFilter(\'particuliers\', this)">Particuliers</button>
        <div class="cosmos-sep"></div>
        <a href="' . esc_url($about_url) . '" class="cosmos-btn cosmos-link-btn">About</a>
        <a href="' . esc_url($contact_url) . '" class="cosmos-btn cosmos-link-btn">Contact</a>
    </div>

    <div id="cosmos-wrapper">
        <div id="cosmos-layout">
            <div class="cosmos-col" id="col-1"></div>
            <div class="cosmos-col" id="col-2"></div>
            <div class="cosmos-col" id="col-3"></div>
            <div class="cosmos-col" id="col-4"></div>
        </div>
    </div>

    <script>
    (function() {
        if (history.scrollRestoration) { history.scrollRestoration = "manual"; }

        let allImagesData = ' . $json_images . ';
        let currentQueue = []; 
        let isLoading = false; 
        let cols = []; 
        let videoObserver = null; 
        let currentlyPlayingDiv = null;
        let currentCategory = "all";
        let lenis; 

        // --- AJOUT : lit ?filter=... dans l\'URL (IMPORTANT: pas "cat" car WP l\'utilise pour les Archives) ---
        function getStartCategoryFromUrl() {
            try {
                const url = new URL(window.location.href);
                const cat = (url.searchParams.get("filter") || "").toLowerCase().trim();
                const allowed = ["all", "artistes", "pro", "particuliers"];
                return allowed.includes(cat) ? cat : "all";
            } catch(e) {
                return "all";
            }
        }

        // --- AJOUT : met à jour l\'URL sans recharger ---
        function setUrlCategory(category) {
            try {
                const url = new URL(window.location.href);
                if (category === "all") url.searchParams.delete("filter");
                else url.searchParams.set("filter", category);
                history.replaceState(null, "", url.toString());
            } catch(e) {}
        }

        // --- AJOUT : active visuellement le bon bouton sans toucher About/Contact ---
        function setActiveButtonByCategory(category) {
            const btns = document.querySelectorAll("#cosmos-nav-container button.cosmos-btn");
            btns.forEach(b => b.classList.remove("active"));

            let targetText = "";
            if (category === "all") targetText = "Tout";
            if (category === "artistes") targetText = "Artistes";
            if (category === "pro") targetText = "Professionnels";
            if (category === "particuliers") targetText = "Particuliers";

            btns.forEach(b => {
                if ((b.textContent || "").trim().toLowerCase() === targetText.toLowerCase()) {
                    b.classList.add("active");
                }
            });
        }

        const initCosmos = function() {
            // --- REGLAGES DE LA PHYSIQUE ---
            if (typeof Lenis !== "undefined") {
                lenis = new Lenis({
                    duration: 2.2,       // Augmenté : Plus d\'inertie (glisse longtemps)
                    easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
                    direction: "vertical",
                    smooth: true,
                    mouseMultiplier: 0.6, // Réduit : Il faut scroller plus physiquement pour avancer

                    // --- REGLAGES MOBILE ---
                    smoothTouch: true,    // FORCE l\'effet sur téléphone
                    touchMultiplier: 0.8, // Réduit : Le doigt doit bouger plus pour scroller (sensation de poids)
                });

                function raf(time) {
                    lenis.raf(time);
                    requestAnimationFrame(raf);
                }
                requestAnimationFrame(raf);
            }

            cols = [ document.getElementById("col-1"), document.getElementById("col-2"), document.getElementById("col-3"), document.getElementById("col-4") ];
            if (!cols[0]) return;

            if ("IntersectionObserver" in window) {
                videoObserver = new IntersectionObserver((entries) => {
                    entries.forEach(entry => {
                        if (!entry.isIntersecting && entry.target.classList.contains("playing")) stopVideo(entry.target);
                    });
                }, { threshold: 0 });
            }

            // --- MODIF : démarre sur la catégorie venant de l\'URL ---
            const startCat = getStartCategoryFromUrl();
            currentCategory = startCat;
            setActiveButtonByCategory(startCat);
            applyFilter(startCat);

            window.addEventListener("scroll", checkScroll, { passive: true });
        };

        function checkScroll() {
            if (isLoading) return;
            const scrollTop = window.scrollY || document.documentElement.scrollTop;
            const windowHeight = window.innerHeight;
            const docHeight = document.documentElement.scrollHeight;

            if (scrollTop + windowHeight >= docHeight - 1500) {
                isLoading = true; 
                addImages(6); 
                if(lenis) setTimeout(() => { lenis.resize(); }, 100);
                setTimeout(() => { isLoading = false; }, 300); 
            }
        }

        function getYoutubeId(url) {
            if (!url) return null;
            const regExp = /^.*(?:(?:youtu\.be\/|v\/|vi\/|u\/\w\/|embed\/|shorts\/)|(?:(?:watch)?\?v(?:i)?=|\&v(?:i)?=))([^#\&\?]*).*/;
            const match = url.match(regExp);
            return (match && match[1].length == 11) ? match[1] : null;
        }

        function stopVideo(div) {
            if (div && div.dataset.backupHtml) {
                div.innerHTML = div.dataset.backupHtml;
                div.classList.remove("playing");
                if (videoObserver) videoObserver.unobserve(div);
                if (currentlyPlayingDiv === div) currentlyPlayingDiv = null;
            }
        }

        function addImages(count) {
            let source = (currentCategory === "all") ? allImagesData : allImagesData.filter(img => img.cat.includes(currentCategory));
            if (source.length === 0) return;

            if (currentQueue.length < count) {
                let refill = shuffle([...source]);
                currentQueue = currentQueue.concat(refill);
            }

            const batch = currentQueue.splice(0, count);

            batch.forEach((imgData) => {
                const div = document.createElement("div"); div.className = "cosmos-item";
                const videoId = getYoutubeId(imgData.video);

                let htmlContent = `<img src="${imgData.url}" width="${imgData.w}" height="${imgData.h}" loading="lazy" style="aspect-ratio:${imgData.w}/${imgData.h};">`;

                if (videoId) {
                    div.onclick = function() {
                        if (this.classList.contains("playing")) return;
                        if (currentlyPlayingDiv && currentlyPlayingDiv !== this) stopVideo(currentlyPlayingDiv);
                        this.dataset.backupHtml = this.innerHTML;
                        this.style.height = this.offsetHeight + "px";
                        this.classList.add("playing");
                        this.innerHTML = `<iframe src="https://www.youtube.com/embed/${videoId}?autoplay=1&rel=0" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen style="width:100%;height:100%;border:none;"></iframe>`;
                        currentlyPlayingDiv = this;
                        if (videoObserver) videoObserver.observe(this);
                    };
                }
                div.innerHTML = htmlContent;

                let shortestIndex = 0; 
                let minVal = 9999999;
                for(let i=0; i < cols.length; i++) { 
                    if (cols[i].offsetHeight < minVal) { 
                        minVal = cols[i].offsetHeight; 
                        shortestIndex = i; 
                    } 
                }
                if (cols[shortestIndex]) { cols[shortestIndex].appendChild(div); }
            });
        }

        function shuffle(array) {
            let currentIndex = array.length, randomIndex;
            let arrayCopy = [...array];
            while (currentIndex != 0) {
                randomIndex = Math.floor(Math.random() * currentIndex); currentIndex--;
                [arrayCopy[currentIndex], arrayCopy[randomIndex]] = [arrayCopy[randomIndex], arrayCopy[currentIndex]];
            }
            return arrayCopy;
        }

        // --- MODIF : on garde cosmosFilter pour compat ---
        window.cosmosFilter = function(category, btnElement) {
            // Ne touche pas aux liens About/Contact
            document.querySelectorAll("#cosmos-nav-container button.cosmos-btn").forEach(b => b.classList.remove("active"));
            if(btnElement) btnElement.classList.add("active");
            applyFilter(category);
        };

        // --- AJOUT : celui-ci met à jour l\'URL (?filter=...), puis filtre ---
        window.cosmosSetFilter = function(category, btnElement) {
            document.querySelectorAll("#cosmos-nav-container button.cosmos-btn").forEach(b => b.classList.remove("active"));
            if(btnElement) btnElement.classList.add("active");
            setUrlCategory(category);
            applyFilter(category);
        };

        function applyFilter(category) {
            currentCategory = category;
            cols.forEach(c => c.innerHTML = ""); 

            if(lenis) lenis.scrollTo(0, { immediate: true });
            else window.scrollTo(0, 0);

            let filtered = (category === "all") ? allImagesData : allImagesData.filter(img => img.cat.includes(category));
            currentQueue = shuffle(filtered);
            if (filtered.length > 0) addImages(12); 
            if(lenis) setTimeout(() => lenis.resize(), 200);
        }

        if (document.readyState === "loading") { document.addEventListener("DOMContentLoaded", initCosmos); } else { initCosmos(); }
    })();
    </script>
    ';
    return $output;
}
